(window.webpackJsonp=window.webpackJsonp||[]).push([[10],{288:function(e,n,r){"use strict";r.r(n);var t=r(64),component=Object(t.a)({},(function(){var e=this,n=e.$createElement;e._self._c;return e._m(0)}),[function(){var e=this,n=e.$createElement,r=e._self._c||n;return r("div",{staticClass:"container mt-5"},[r("h3",[e._v("Informationen zu Immobilien Freistaat Bayern")]),e._v(" "),r("div",[r("p",[e._v("\n      Immobilien Freistaat Bayern untersteht dem Bauministerium. Es ist für das kaufmännische Facilitymanagement\n      von staatlichen Gebäuden zuständig, beispielsweise die Organisation von Ausschreibungen und die Gestaltung der entsprechenden Verträge.\n      Es wurde vom Bauministerium beauftragt, entsprechende Dachflächen für Photovoltaik auszuschreiben. Vor etwa 3 Jahren wurden entsprechende\n      Verträge erstellt.\n      Die Eignung der erstellten Verträge wurde bei Unternehmen in der Energiebranche (u.A. Energiegenossenschaften) abgefragt.\n      Obwohl viele Firmen und Energiegenossenschaften zurückmeldeten, dass diese Verträge für Investoren nicht tragbar\n      seien und sie sich auf diese Verträge nicht bewerben werden, wurden die Dachflächen mit genau diesen Verträgen ausgeschrieben.\n      Deshalb verwundert es nicht, dass es auf die wenigen Ausschreibungen der letzten Jahre kaum Bewerbungen von Investoren gab.\n      In einem Telefonat mit Immobilien Freistaat Bayern wurde sich über die wenige Resonanz aus der Wirtschaft gewundert.\n    ")]),e._v(" "),r("p",[e._v("\n      Aktuell werden diese Verträge überarbeitet. Sie sollen nun investorenfreundlicher werden, sodass damit hoffentlich bald Pachtverträge mit z.B.\n      Energiegenossenschaften geschlossen werden können. Diese Verträge gelten dann für alle Gebäude des Freistaats Bayern.\n      Ein Investor kann auch ohne Ausschreibung einer bestimmten Dachfläche Interesse bei der jeweiligen Regionalverwaltung von Immobilien Freistaat Bayern Interesse bekunden.\n      Diese Fläche kann dann, gegebenenfalls mit Ausschreibung, verpachtet werden.\n    ")]),e._v(" "),r("p",[e._v("\n      Dass hier über einen längeren Zeitraum hinweg Verträge angeboten wurden, die Photovoltaik nicht ermöglichten, ist äußerst\n      bedauernswert. Dadurch ist wertvolle Zeit für die Beschleunigung der Energiewende verloren gegangen.\n      Wir hoffen sehr, dass die neuen Verträge mit Energiegenossenschaften und\n      anderen Partnern abgesprochen wurden und unbürokratisch die Verpachtung von Dachflächen für die Energiewende ermöglichen.\n    ")])])])}],!1,null,null,null);n.default=component.exports}}]);
